theorem output_length (g : DirectedGraph) (w : g.Edge → Nat) (s : g.V) (n : Nat) (hV : g.Vcard = n) :
  let dist := dijkstra_ref g w s n;
  dist.length = n

theorem output_type_option (g : DirectedGraph) (w : g.Edge → Nat) (s : g.V) (n : Nat) :
  let dist := dijkstra_ref g w s n;
  ∀ v : Fin n, dist[v].isSome ∨ dist[v].isNone

theorem source_distance (g : DirectedGraph) (w : g.Edge → Nat) (s : g.V) (n : Nat) (hV : g.Vcard = n) :
  let dist := dijkstra_ref g w s n;
  dist[⟨s.1, hV ▸ Nat.lt_succ_self _⟩] = some 0
